import{_ as t,o as a,c as r,ai as i}from"./chunks/framework.CsYGeNYI.js";const p=JSON.parse('{"title":"Contributing to the OpenSoul Threat Model","description":"","frontmatter":{},"headers":[],"relativePath":"security/CONTRIBUTING-THREAT-MODEL.md","filePath":"security/CONTRIBUTING-THREAT-MODEL.md","lastUpdated":1771906665000}'),o={name:"security/CONTRIBUTING-THREAT-MODEL.md"};function n(s,e,d,l,h,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="contributing-to-the-opensoul-threat-model" tabindex="-1"><a class="header-anchor" href="#contributing-to-the-opensoul-threat-model">#</a> Contributing to the OpenSoul Threat Model</h1><p>Thanks for helping make OpenSoul more secure. This threat model is a living document and we welcome contributions from anyone - you don&#39;t need to be a security expert.</p><h2 id="ways-to-contribute" tabindex="-1"><a class="header-anchor" href="#ways-to-contribute">#</a> Ways to Contribute</h2><h3 id="add-a-threat" tabindex="-1"><a class="header-anchor" href="#add-a-threat">#</a> Add a Threat</h3><p>Spotted an attack vector or risk we haven&#39;t covered? Open an issue on <a href="https://github.com/opensoul/trust/issues" target="_blank" rel="noreferrer">opensoul/trust</a> and describe it in your own words. You don&#39;t need to know any frameworks or fill in every field - just describe the scenario.</p><p><strong>Helpful to include (but not required):</strong></p><ul><li>The attack scenario and how it could be exploited</li><li>Which parts of OpenSoul are affected (CLI, gateway, channels, ClawHub, MCP servers, etc.)</li><li>How severe you think it is (low / medium / high / critical)</li><li>Any links to related research, CVEs, or real-world examples</li></ul><p>We&#39;ll handle the ATLAS mapping, threat IDs, and risk assessment during review. If you want to include those details, great - but it&#39;s not expected.</p><blockquote><p><strong>This is for adding to the threat model, not reporting live vulnerabilities.</strong> If you&#39;ve found an exploitable vulnerability, see our <a href="https://trust.opensoul.ai" target="_blank" rel="noreferrer">Trust page</a> for responsible disclosure instructions.</p></blockquote><h3 id="suggest-a-mitigation" tabindex="-1"><a class="header-anchor" href="#suggest-a-mitigation">#</a> Suggest a Mitigation</h3><p>Have an idea for how to address an existing threat? Open an issue or PR referencing the threat. Useful mitigations are specific and actionable - for example, &quot;per-sender rate limiting of 10 messages/minute at the gateway&quot; is better than &quot;implement rate limiting.&quot;</p><h3 id="propose-an-attack-chain" tabindex="-1"><a class="header-anchor" href="#propose-an-attack-chain">#</a> Propose an Attack Chain</h3><p>Attack chains show how multiple threats combine into a realistic attack scenario. If you see a dangerous combination, describe the steps and how an attacker would chain them together. A short narrative of how the attack unfolds in practice is more valuable than a formal template.</p><h3 id="fix-or-improve-existing-content" tabindex="-1"><a class="header-anchor" href="#fix-or-improve-existing-content">#</a> Fix or Improve Existing Content</h3><p>Typos, clarifications, outdated info, better examples - PRs welcome, no issue needed.</p><h2 id="what-we-use" tabindex="-1"><a class="header-anchor" href="#what-we-use">#</a> What We Use</h2><h3 id="mitre-atlas" tabindex="-1"><a class="header-anchor" href="#mitre-atlas">#</a> MITRE ATLAS</h3><p>This threat model is built on <a href="https://atlas.mitre.org/" target="_blank" rel="noreferrer">MITRE ATLAS</a> (Adversarial Threat Landscape for AI Systems), a framework designed specifically for AI/ML threats like prompt injection, tool misuse, and agent exploitation. You don&#39;t need to know ATLAS to contribute - we map submissions to the framework during review.</p><h3 id="threat-ids" tabindex="-1"><a class="header-anchor" href="#threat-ids">#</a> Threat IDs</h3><p>Each threat gets an ID like <code>T-EXEC-003</code>. The categories are:</p><table tabindex="0"><thead><tr><th>Code</th><th>Category</th></tr></thead><tbody><tr><td>RECON</td><td>Reconnaissance - information gathering</td></tr><tr><td>ACCESS</td><td>Initial access - gaining entry</td></tr><tr><td>EXEC</td><td>Execution - running malicious actions</td></tr><tr><td>PERSIST</td><td>Persistence - maintaining access</td></tr><tr><td>EVADE</td><td>Defense evasion - avoiding detection</td></tr><tr><td>DISC</td><td>Discovery - learning about the environment</td></tr><tr><td>EXFIL</td><td>Exfiltration - stealing data</td></tr><tr><td>IMPACT</td><td>Impact - damage or disruption</td></tr></tbody></table><p>IDs are assigned by maintainers during review. You don&#39;t need to pick one.</p><h3 id="risk-levels" tabindex="-1"><a class="header-anchor" href="#risk-levels">#</a> Risk Levels</h3><table tabindex="0"><thead><tr><th>Level</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Critical</strong></td><td>Full system compromise, or high likelihood + critical impact</td></tr><tr><td><strong>High</strong></td><td>Significant damage likely, or medium likelihood + critical impact</td></tr><tr><td><strong>Medium</strong></td><td>Moderate risk, or low likelihood + high impact</td></tr><tr><td><strong>Low</strong></td><td>Unlikely and limited impact</td></tr></tbody></table><p>If you&#39;re unsure about the risk level, just describe the impact and we&#39;ll assess it.</p><h2 id="review-process" tabindex="-1"><a class="header-anchor" href="#review-process">#</a> Review Process</h2><ol><li><strong>Triage</strong> - We review new submissions within 48 hours</li><li><strong>Assessment</strong> - We verify feasibility, assign ATLAS mapping and threat ID, validate risk level</li><li><strong>Documentation</strong> - We ensure everything is formatted and complete</li><li><strong>Merge</strong> - Added to the threat model and visualization</li></ol><h2 id="resources" tabindex="-1"><a class="header-anchor" href="#resources">#</a> Resources</h2><ul><li><a href="https://atlas.mitre.org/" target="_blank" rel="noreferrer">ATLAS Website</a></li><li><a href="https://atlas.mitre.org/techniques/" target="_blank" rel="noreferrer">ATLAS Techniques</a></li><li><a href="https://atlas.mitre.org/studies/" target="_blank" rel="noreferrer">ATLAS Case Studies</a></li><li><a href="./THREAT-MODEL-ATLAS">OpenSoul Threat Model</a></li></ul><h2 id="contact" tabindex="-1"><a class="header-anchor" href="#contact">#</a> Contact</h2><ul><li><strong>Security vulnerabilities:</strong> See our <a href="https://trust.opensoul.ai" target="_blank" rel="noreferrer">Trust page</a> for reporting instructions</li><li><strong>Threat model questions:</strong> Open an issue on <a href="https://github.com/opensoul/trust/issues" target="_blank" rel="noreferrer">opensoul/trust</a></li><li><strong>General chat:</strong> Discord #security channel</li></ul><h2 id="recognition" tabindex="-1"><a class="header-anchor" href="#recognition">#</a> Recognition</h2><p>Contributors to the threat model are recognized in the threat model acknowledgments, release notes, and the OpenSoul security hall of fame for significant contributions.</p>',33)])])}const g=t(o,[["render",n]]);export{p as __pageData,g as default};
